sql:
SELECT COUNT(*) AS high_priority_request_count
FROM barcode_generation_requests
WHERE priority = 'high';

SELECT status, COUNT(*) AS request_count
FROM barcode_generation_requests
GROUP BY status;

SELECT template_id
FROM template_usage_logs
WHERE used_count > 0;

SELECT template_id, SUM(used_count) AS total_usages
FROM template_usage_logs
GROUP BY template_id;

SELECT request_id, status, priority
FROM barcode_generation_requests
WHERE status = 'completed' AND priority = 'high';

SELECT barcode_id, barcode_type, label_format
FROM barcodes
WHERE resolution >= 600;

external_knowledge:
- Frequently used templates are those with a total usage greater than 0; 
- Completed barcode requests are those with a 'completed' status; 
- Printed barcodes are those with a 'printed' flag set to 1; 
- Request groups are categorized based on the request date using the NTILE function, dividing the requests into five groups; 
- Address labels are considered significant if there are more than two associated with a barcode.

sql:
SELECT template_id, used_count
FROM template_usage_logs
ORDER BY used_count DESC;

SELECT COUNT(*) AS printed_labels_count
FROM address_labels
WHERE printed = 1;

SELECT template_name
FROM label_templates
WHERE template_id = 0;

SELECT COUNT(DISTINCT user_id) AS total_unique_users
FROM barcode_generation_requests
WHERE status = 'completed';

SELECT address_details, dimensions
FROM address_labels
WHERE printed = 0;

SELECT MAX(priority) AS peak_priority
FROM barcode_generation_requests
WHERE request_date = '2023-08-05';
